/**
 * Create a JSON Response with proper headers.
 */
export function jsonResponse(data: unknown, status: number = 200): Response {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json; charset=utf-8' },
  });
}

import { Hono } from '../hono';
import { expect, test } from 'vitest';

test('GET route returns response', async () => {
  const app = new Hono();
  app.get('/hello', (c) => c.text('Hello!'));

  const res = await app.request('/hello');
  expect(res.status).toBe(200);
  expect(await res.text()).toBe('Hello!');
});

test('POST route returns response', async () => {
  const app = new Hono();
  app.post('/data', (c) => c.json({ ok: true }));

  const res = await app.request('/data', { method: 'POST' });
  expect(res.status).toBe(200);
  const body = await res.json();
  expect(body.ok).toBe(true);
});

test('unknown route returns 404', async () => {
  const app = new Hono();
  const res = await app.request('/nonexistent');
  expect(res.status).toBe(404);
});

if (this.router && console?.warn) {
  console.warn('[hono] Warning: middleware registered after routes. Middleware should be added before routes for correct execution order.');
}
